public int[] frontPiece(int[] nums) {
    int len = nums.length;
    int[] result;

    if(len > 2) {
        result = new int[2];
    } else {
        result = new int[len];
    }

    for(int i = 0; i < result.length; i++) {
        result[i] = nums[i];
    }

    return result;
}

